1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	type Item = { type: string };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
17	
18	const isComponentBlock = (items: Item[]): boolean =>
19	  items.length === COMPONENT_BLOCK_SIZE
20	  && COMPONENT_TYPES.includes(items[0].type)
21	  && items.every((i) => i.type === items[0].type);
22	
23	export function quote(_customer: { yearsWithMHPCO: number }, items: Item[]): number {
24	  if (isComponentBlock(items)) {
25	    return COMPONENT_BLOCK_PREMIUM + PROCESSING_FEE;
26	  }
27	  const itemsTotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
28	  return itemsTotal + PROCESSING_FEE;
29	}
30	
31	export function claim(): number {
32	  return undefined as unknown as number;
33	}
